import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const I=JSON.parse('{"title":"2、女教皇【II】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/2、女教皇【II】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/2、女教皇【II】.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/2、女教皇【II】.md"};function _(d,a,i,l,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"_2、女教皇【ii】",tabindex:"-1"},[n("2、女教皇【II】 "),e("a",{class:"header-anchor",href:"#_2、女教皇【ii】","aria-label":'Permalink to "2、女教皇【II】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="女教皇" tabindex="-1">女教皇 <a class="header-anchor" href="#女教皇" aria-label="Permalink to &quot;女教皇&quot;">​</a></h1><p>女教皇</p><p>A+4800<br> 替身外貌：<br> 外型是披着一团看起来像蓑衣的皮毛，戴着部落面具的生物，眼神凶恶，牙齿外露，皮毛呈现液态金属状，上面长了一对肌肉发达的手臂。</p><p>替身数据：<br> 破坏力C<br> 速度B（格挡防御）<br> 射程A<br> 持续力A<br> 精密动作性D<br> 成长性D</p><p>替身对应主属性：决心</p><p>替身能力：<br> 远程替身：作为远程替身，射程距离为【决心×100】米，替身能在这个范围内自由行动。若替身的行动距离超出了你的敏感范围，其会根据你预先设置的行动目的进行活动，当完成目标或者明显无法完成目标时，其会返回。</p><p>无机物变形：女教皇能变身成任何类型无支线的无机物，并且也能变成各种相当复杂的构造，变形后的物品能进行简单的使用，这视为B级变形来源的伪装效果。若要进行对抗，则对方需要进行识破伪装为目的的调查检定对抗你的【决心+隐秘+伪装】，对方胜出则会识破你的伪装。</p><p>吞噬物质：女教皇有比钻石还要坚硬的牙齿，以吞咬作为主要攻击方式，只要在女祭司前方的一半触及范围内都属于其可以同时吞咬范围内，可以同时对其攻击。</p><p>此外还能吞噬各种无机物增加自己的体型（岩石、金属、玻璃等），不论是通过咬来攻击敌人还是吞噬无机物都需要以一个标准动作控制。<br> 而吞噬无机物时每吞噬1体积就能为女教皇增加1体积和1点替身使用检定加值，通过吞噬增加的体积与检定上限为【决心×2】点，这视为D级夺权效果。<br> 替身可以吐出物质以减小自身的体积，但这也会丢失吞噬带来的替身检定加值。<br> 增加的体积不会为你带来生命值上限，只会影响替身的触及范围。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const f=r(o,[["render",_]]);export{I as __pageData,f as default};
